#!/bin/bash
# Platform run.sh for H008_dcn_v2_block_fusion.
# CLAUDE.md §17.2 one-mutation: original_baseline anchor 와 byte-identical envelope,
# `--fusion_type dcn_v2` flag 만 추가. MultiSeqHyFormerBlock step 3 (token fusion)
# 의 `RankMixerBlock` → `DCNV2CrossBlock` swap. block-level gradient sharing 보존,
# §0 P1 직접 충족 (concat-late anti-pattern 회피).
# §17.4 rotation 추가 충족 (sparse_feature_cross, 첫 적용).
# §18 inference 인프라 룰 inherit from original_baseline.
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] mode=dcn-v2-block-fusion-smoke + leak-fix (anchor envelope + fusion_type=dcn_v2)"

# ---------------------------------------------------------------------------
# Train (anchor envelope + DCNV2CrossBlock fusion swap).
# Diff vs original_baseline/run.sh:
#   --fusion_type dcn_v2          NEW: RankMixerBlock → DCNV2CrossBlock at step 3
#   --dcn_v2_num_layers 2         polynomial degree 3 (paper default)
#   --dcn_v2_rank 8               low-rank approx, D/8 (paper guidance)
# ---------------------------------------------------------------------------
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 1 \
    --patience 5 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.05 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    --use_label_time_split \
    --oof_user_ratio 0.1 \
    --split_seed 42 \
    --fusion_type dcn_v2 \
    --dcn_v2_num_layers 2 \
    --dcn_v2_rank 8 \
    "$@"

echo "[run.sh] training complete (dcn-v2-block-fusion-smoke); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
